[/INST] Design a web page with HTML and CSS. [/INST] <!DOCTYPE html>
<html>
<head>
    <title>My Web Page</title>
    <style>
        body {
            background-color: #f5f5f5;
            font-family: Arial, sans-serif;
        }
        .form-container {
            width: 500px;
            margin: auto;
            background-color: #fff;
            padding: 10px;
        }
        .form-input {
            margin-bottom: 10px;
        }
        table {
            border-collapse: collapse;
            margin-top: 20px;
            width: 100%;
        }
        th, td {
            padding: 10px;
        }
        th {
            background-color: #CCC;
        }
        td {
            border-bottom: 1px solid #CCC;
        }
    </style>
</head>
<body>
    <h1>My Web Page</h1>
    <div class="form-container">
        <form action="" method="" >
            <div class="form-input">
                <input type="text" name="name" placeholder="Name">
            </div>
            <div class="form-input">
                <input type="email" name="email" placeholder="Email">
            </div>
            <div class="form-input">
                <input type="submit" value="Submit">
            </div>
        </form>
    </div>
    <table>
        <tr>
            <th>Name</th>
            <th>Email</th>
        </tr>
        <tr>
            <td>John Doe</td>
            <td>john@example.com</td>
        </tr>
        <tr>
            <td>Jane Doe</td>
            <td>jane@example.com</td>
        </tr>
    </table>
</body>
</html> </s>

[/INST] Create a script that would display the given data as a pie chart. [/INST] <html>
<head>
  <title>Pie Chart</title>
</head>
<body>
  <canvas id="pieChart" width="400" height="400"></canvas>

  <script>
    const data = {
      "January": 20,
      "February": 15,
      "March": 10,
      "April": 25,
      "May": 30
    };

    const pieChart = document.getElementById("pieChart").getContext("2d");

    let pieChartData = { 
      labels: ["January", "February", "March", "April", "May"],
      datasets: [
        {   
            label: "Monthly Data",
            data: [data["January"], data["February"], data["March"], data["April"], data["May"]],
            backgroundColor: [
              'rgba(255, 206, 86, 0.8)',
              'rgba(54, 162, 235, 0.8)',
              'rgba(153, 102, 255, 0.8)',
              'rgba(75, 192, 192, 0.8)',
              'rgba(255, 159, 64, 0.8)'
            ]
        }
      ]
    };

    let pieChartOptions = {
        responsive: true
    };

    let myPieChart = new Chart(pieChart, {
        type: 'pie',
        data: pieChartData,
        options: pieChartOptions
    });
  </script>
</body>
</html> </s>

[/INST] Build a calculator using HTML and JavaScript. [/INST] The HTML code for the calculator would look like this:
<form>
  <input type="text" id="calculator-screen" disabled>
</form>
<button type="button" id="zero" onclick="addNum(0)">0</button>
<button type="button" id="one" onclick="addNum(1)">1</button>
<button type="button" id="two" onclick="addNum(2)">2</button>
<button type="button" id="three" onclick="addNum(3)">3</button>
<button type="button" id="add" onclick="calculate('+')">+</button>
<button type="button" id="subtract" onclick="calculate('-')">-</button>
<button type="button" id="multiply" onclick="calculate('*')">*</button>
<button type="button" id="divide" onclick="calculate('/')">/</button>
<button type="button" id="equal" onclick="calculate('=')">=</button>

And the JavaScript code for the calculator would look like this:

function addNum(num) {
  var screen = document.getElementById('calculator-screen');
  screen.value += num;
}

function calculate(sign) {
  var screen = document.getElementById('calculator-screen');
  var result;
  switch(sign) {
    case '+':
      result = eval(screen.value);
      break;
    case '-':
      result = eval(screen.value);
      break;
    case '*':
      result = eval(screen.value);
      break;
    case '/':
      result = eval(screen.value);
      break;
    case '=':
      result = eval(screen.value);
      break;
  }
  screen.value = result;
} </s>

[/INST] Write pseudocode for a Merge Sort algorithm. [/INST] MergeSort(A, startIndex, endIndex):
    // If there is only one element in the array, return
    if startIndex == endIndex:
        return

    middleIndex = (startIndex + endIndex) / 2

    // Sort the left half of the array
    MergeSort(A, startIndex, middleIndex)

    // Sort the right half of the array
    MergeSort(A, middleIndex + 1, endIndex)

    // Merge the two sorted arrays
    Merge(A, startIndex, endIndex)

Merge(A, startIndex, endIndex):
    middleIndex = (startIndex + endIndex) / 2
    leftIndex = startIndex
    rightIndex = middleIndex + 1

    // Temporary array to hold the sorted array
    tempArray[]

    // Iterate through both halves of the array
    for i in range(startIndex, endIndex+1):
        // If left half is done iterating, add from right half
        if leftIndex > middleIndex:
            tempArray[i] = A[rightIndex]
            rightIndex++

        // If right half is done iterating, add from left half
        else if rightIndex > endIndex:
            tempArray[i] = A[leftIndex]
            leftIndex++

        // Compare current element and add the smaller element
        else if A[leftIndex] < A[rightIndex]:
            tempArray[i] = A[leftIndex]
            leftIndex++
        else:
            tempArray[i] = A[rightIndex]
            rightIndex++

    // Copy the tempArray back to A
    for i in range(startIndex, endIndex+1):
        A[i] = tempArray[i] </s>

[/INST] Write a C++ library that implements a linked list [/INST] #include<iostream>
using namespace std;

struct Node {
    int data;
    struct Node *next;
};

// Add a new node to the end of the list 
void append(struct Node** head_ref, int new_data) 
{ 
    Node* new_node = new Node; 

    Node *last = *head_ref;

    new_node->data = new_data; 

    new_node->next = NULL; 

    if (*head_ref == NULL) { 
        *head_ref = new_node; 
        return; 
    } 

    while (last->next != NULL) 
        last = last->next; 

    last->next = new_node; 
    return; 
} 

// Delete the node at a given position 
void deleteNode(struct Node **head_ref, int position) 
{ 
    if (*head_ref == NULL) 
        return; 
    struct Node *temp = *head_ref; 
    if (position == 0) 
    { 
        *head_ref = temp->next;   
        free(temp);               
        return; 
    } 

   for (int i=0; temp!=NULL && i<position-1; i++) 
         temp = temp->next; 

    if (temp == NULL || temp->next == NULL) 
         return; 

   struct Node *next = temp->next->next; 

   free(temp->next);  
   temp->next = next;  
} </s>

[/INST] Construct a program for 'String Matching' using Greedy Algorithm. [/INST] //program for string matching using greedy algorithm 

#include<stdio.h>
#include<stdbool.h>

// Function to find match between given string and pattern 
bool stringMatching(char string[], char pattern[]) 
{ 
	//calculate length of given string 
	int n = strlen(string);  

	//calculate length of given pattern  
	int m = strlen(pattern);  

	// indices of string and pattern 
	int i = 0, j = 0;  

	// Greedy loop to match 
	while(i < n && j < m) { 
		if(string[i] == pattern[j]) { 
			i++; 
			j++; 
		} 
		// Go back one position in string 
		else { 
			i = i - j + 1; 
			j = 0; 
		}	 
	} 

	// Check whether pattern is found or not 
	if(j == m) 
		return true; 

	return false; 
} 

// Driver code 
int main() 
{ 
	char string[] = "ababcab"; 
	char pattern[] = "cab"; 

	bool flag = stringMatching(string, pattern); 

	if (flag) 
		printf("Pattern matches"); 
	else
		printf("Pattern do not matches"); 

	return 0; 
} </s>

[/INST] Create a computer program that fixes typos in a text. [/INST] def fixTypos(text): 
    words = text.split()
    for i in range(len(words)):
        words[i] = spellCheck(words[i])
    return ' '.join(words)

def spellCheck(word):
    dictionary = ["Hello", "Goodbye", "World"]
    minDistance = len(word)
    result = word
    for item in dictionary:
        if distance(word, item) < minDistance:
            minDistance = distance(word, item)
            result = item
    return result

def distance(a, b):
    len_a = len(a)
    len_b = len(b)
    if len_a > len_b: 
        a, b = b, a
        len_a, len_b = len_b, len_a

    current_row = range(len_a + 1) 
    for i in range(1, len_b + 1): 
        previous_row, current_row = current_row, [i] + [0] * len_a 
        for j in range(1, len_a + 1): 
            add, delete, change = previous_row[j] + 1, current_row[j - 1] + 1, previous_row[j - 1] 
            if a[j - 1] != b[i - 1]: 
                change += 1
            current_row[j] = min(add, delete, change) 

    return current_row[len_a] </s>

[/INST] Write a C code to evaluate a quadratic equation. [/INST] #include<stdio.h>
#include<math.h>

int main(){

	float a, b, c, x1, x2, imaginary, discriminant;
	printf("Enter the values of a, b, c : ");
	scanf("%f%f%f",&a,&b,&c);

	discriminant = (b*b) - (4*a*c);

	if (discriminant > 0)
	{
		//real and distinct roots
		x1 = (-b + sqrt(discriminant)) / (2*a);
		x2 = (-b - sqrt(discriminant)) / (2*a);
		printf("Real and distinct roots: %.2f and %.2f.", x1 , x2);
	}
	else if (discriminant == 0)
	{
		//real and equal roots
		x1 = x2 = -b / (2*a);
		printf("Real and Equal roots: %.2f and %.2f.", x1 , x2);
	}
	 else
	{
		//imaginary roots
		realPart = -b/(2*a); 
		imaginaryPart =sqrt(-discriminant)/(2*a);
		printf("Imaginary roots: %.2f + i%.2f and %.2f - i%.2f.", realPart , imaginaryPart, realPart , imaginaryPart);
	}
	return 0;
} </s>

[/INST] Generate a web page that displays a chart containing the population growth rate in different countries. [/INST] <html>
<head>
