                        'rgba(255, 99, 132, 0.2)',
                    ],
                    borderColor: [
                        'rgba(255, 99, 132, 1)',
                    ],
                    borderWidth: 1
                    }]
            },
            options: {}
        });
    </script>
</body>
</html> </s>

[/INST] Write a c program that takes a string from the user and reverses it [/INST] #include<stdio.h> 
#include<string.h> 

// Function to reverse any sequence starting with pointer 
// begin and ending with pointer end 
void Reverse(char* begin, char* end) 
{ 
    char temp; 
    while (begin < end) { 
        temp = *begin; 
        *begin++ = *end; 
        *end-- = temp; 
    } 
} 

// Function to reverse words*/ 
void ReverseWords(char* s) 
{ 
    char* word_begin = s; 

    // Word boundary 
    char* temp = s; 

    // Revert string 
    Reverse(s, temp); 

    // Revert each word 
    while (*temp) { 
        temp++; 
        if (*temp == '\0') { 
            Reverse(word_begin, temp - 1); 
        } else if (*temp == ' ') { 
            Reverse(word_begin, temp - 1); 
            word_begin = temp + 1; 
        } 
    } 
} 

// Driver code 
int main() 
{ 
    char s[] = "Welcome to Geeksforgeeks"; 
    char* temp = s; 
    ReverseWords(s); 
    printf("%s", s); 

    return 0; 
} </s>

[/INST] Create a web page that displays the following data as a bar chart. [/INST] <html>
<head>
  <title>Bar Chart</title>
</head>
<body>
  <canvas id="barChart" width="400" height="400"></canvas>

  <script>
    const data = {
      "January": 20,
      "February": 15,
      "March": 10,
      "April": 25,
      "May": 30
    };

    const barChart = document.getElementById("barChart").getContext("2d");

    let barChartData = { 
      labels: ["January", "February", "March", "April", "May"],
      datasets: [
        {   
            label: "Monthly Data",
            data: [data["January"], data["February"], data["March"], data["April"], data["May"]],
            backgroundColor: "#FFCE56"
        }
      ]
    };

    let barChartOptions = {
        responsive: true,
        scales: {
            yAxes: [{
                ticks: {
                    beginAtZero:true
                }
            }]
        }
    };

    let myBarChart = new Chart(barChart, {
        type: 'bar',
        data: barChartData,
        options: barChartOptions
    });
  </script>
</body>
</html> </s>

[/INST] Given a data set, write a program that counts the number of instances of each label. [/INST] #include<stdio.h>
#include <string.h>

int main() 
{
    char data[][10] = {"puppy","dog","kitten","cat","puppy","dog","fish","cat"};
    int puppy_count = 0;
    int dog_count = 0;
    int kitten_count = 0;
    int cat_count = 0;
    int fish_count = 0;
    int i;
    int size = sizeof(data)/10;

    for(i=0;i<size;i++)
    {
        if(strcmp(data[i],"puppy")==0)
            puppy_count++;
        if(strcmp(data[i],"dog")==0)
            dog_count++;
        if(strcmp(data[i],"kitten")==0)
            kitten_count++;
        if(strcmp(data[i],"cat")==0)
            cat_count++;
        if(strcmp(data[i],"fish")==0)
            fish_count++;
    }
    printf("puppy count is %d\ndog count is %d\nkitten count is %d\ncat count is %d\nfish count is %d\n",
    puppy_count, dog_count, kitten_count, cat_count, fish_count);

    return 0;
  } </s>
